    def name(self) -> bytes:
        """Get the current value of the name key in global_state state"""
        value = self.app_client.state.global_state.get_value("name")
        if isinstance(value, dict) and "byte[]" in self._struct_classes:
            return _init_dataclass(self._struct_classes["byte[]"], value)  # type: ignore
